var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"대령, 차원 폭풍이 계속 강해지고 있어!","JPN":"大佐、次元の暴風がだんだん強くなってきたぞ！","ENG":"Colonel, the dimensional storm is getting heavier!","TWN":"上校，次元風暴持續增強中欸！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"대체 얼마나 더 들어가야 하는 거지?","JPN":"いったいどこまで進めばいいんだ？","ENG":"How long do we have left?","TWN":"我們到底要進到多深的地方？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"우는 소리 그만해. 내 기억으로는 얼마 안 남았으니까.","JPN":"グズグズするな。俺の記憶が正しければあと少しだ。","ENG":"Stop complaining. If I remember correctly, we’ll get there soon.","TWN":"不要在那邊鬼吼鬼叫的，我記得就快到啦！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"30분 전에도 같은 대답을 들었던 것 같은데?","JPN":"30分前も同じことを聞いた気がするんだが？","ENG":"You said the same thing thirty minutes ago.","TWN":"這句話我30分鐘前就聽過咧？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"여긴 제대로 된 차원 함선도 항해하기 어려운 곳이야.","JPN":"ここはまともな次元艦船でも航海しにくい場所なんだ。","ENG":"Even a proper dimensional ship would have trouble navigating through this storm.","TWN":"一般的艦船根本很難開到這種地方。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이런 수송기는 언제 추락할지 모른다고!","JPN":"こんな輸送機じゃ、いつ墜落してもおかしくないぞ？","ENG":"And we’re in a shabby cargo ship!","TWN":"誰知道這個鬼貨機什麼時候會墜機！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"거 용병 주제에 말이 많군, 메이슨 씨.","JPN":"傭兵なのにかなりおしゃべりだな、メイソンさん。","ENG":"You are a very chatty mercenary, aren’t you, Mr. Mason?","TWN":"傭兵怎麼這麼多話！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"지난번에는 고물 강하선으로 뉴 오하이오를 쫓아가지 않았던가?","JPN":"前におんぼろ降下船でニューオハイオを追いかけたこともあっただろ？","ENG":"I remember the time you chased the New Ohio with a crummy drop ship.","TWN":"上次還不是用那個古董降落艙去追新俄亥俄？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그러다 단체로 공중분해 될 뻔했지! 그런 일은 두 번 다시 사양이야!","JPN":"それで全員空中分解されるところだったんだぞ！　あんなことは二度とご免だ！","ENG":"And we almost got disintegrated in the air! I don’t want to do that again!","TWN":"然後不就差點在空中解體嗎！那麼可怕的事我可不想再經歷第二次！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"공중분해라고 하시니까……. 뭔가 어렴풋이 떠올랐어요.","JPN":"今空中分解と聞いて……ぼんやりと思い出しました。","ENG":"Disintegration... That reminds me of something.","TWN":"說到空中解體……我好像有想起什麼。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"칼 두 자루를 들고 치마를 입지 않은 이상한 여자 분과 싸우면서 공중분해를 다섯 번쯤 당했던 것 같아요.","JPN":"剣を2本持ったスカートを履いていない変な女性の方と戦いながら\\n5回くらい、空中分解された気がします。","ENG":"I think I got disintegrated about five times, fighting a strange woman without a skirt, holding two swords.","TWN":"我和一個手拿著兩把刀，下半身沒穿裙子的奇怪女生在打鬥，同時經歷5次左右的空中解體吧？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"확실하진 않지만……. 무척 아프고 괴로운 기분도 드네요.","JPN":"朧げながら……とても痛くて辛い気分になりますね。","ENG":"I don’t remember it clearly... but I think it was very painful.","TWN":"雖然不太確定……但是感覺非常痛苦難受。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"구체적으로 어떻게 아팠냐면……","JPN":"具体的にどのように痛かったかというと……","ENG":"The pain I felt was like...","TWN":"具體來說是怎麼樣個痛法呢……"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"안 죽어! 안 죽으니까 설명하지 마!","JPN":"死なねえよ！　死なないからもう説明するな！","ENG":"No! We won’t be disintegrated! So stop explaining!","TWN":"別說了！我們不會死的！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"젠장……. 애보기가 따로 없군.","JPN":"ちぇっ……これじゃベビーシッターと変わんねえな。","ENG":"Darn it... I feel like I’m babysitting.","TWN":"該死……還帶個孩子在身邊！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐 하고 있어, 대령! 나한테만 맡기지 말고 그쪽도 좀 달래 줘야지!","JPN":"何してるんだ、大佐！　俺ばかりに任せないでそっちも何か言えよ！","ENG":"What are you doing, Colonel? You have to help me with her!","TWN":"上校，你在幹嘛！怎麼可以都丟給我，你也安慰幾句吧！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"베이비시터 노릇 같은 건 훈련소에서도 배운 적 없어! 전기 쇼크라도 주면 되나?!","JPN":"ベビーシッターの仕事なんて訓練所でも習ったことないぞ！\\n電気ショックでも与えて寝かせてあげればいいのか？","ENG":"I don’t know how to babysit. I never had the training! Maybe I can shock her a little?","TWN":"我在訓練所沒有學過怎麼當保母！要給她電擊嗎？！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그 대사, 나중에 대령이 결혼해서 아이 낳으면 꼭 다시 돌려주지!","JPN":"そのセリフ、今後大佐が結婚して子どもが産まれたらそのまんま返してやる！","ENG":"Let’s see if you do that when you have your own child!","TWN":"等你以後結婚生孩子，我要把這句話原封不動地還給你！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"즐거운 대화 중에 죄송합니다만……","JPN":"楽しい会話中に申し訳ありませんが……","ENG":"I’m sorry to interrupt your jolly little conversation...","TWN":"不好意思，打斷你們愉快的對話……"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"침식체들이 수송기 주변으로 접근하고 있는 것 같은데요?","JPN":"侵食体が輸送機周辺に接近しているようです。","ENG":"But I see C.O.s approaching the ship.","TWN":"侵蝕體似乎正在接近貨機喔？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"왜 안 오나 싶었지. 갈수록 태산이군.","JPN":"いつ来るかとずっと気にしてはいたが。こりゃ泣きっ面に蜂だな。","ENG":"I was wondering when they were going to show up.","TWN":"我還想說怎麼都沒動靜呢？果然是一波未平一波又起！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이대로 가다간 공격당할 거야. 무기는 없어?","JPN":"このままじゃ普通に攻撃されるよ。武器はないの？","ENG":"They’re going to attack us soon. Do we have weapons to fight back?","TWN":"他們一定會來攻擊你們，你們沒有武器嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"잘 모르나 본데 설명을 해 주지.","JPN":"あまり知らないみたいだから説明してやろう。","ENG":"Oh, you don’t know. Let me explain.","TWN":"我看你好像不太明白，我來跟你解釋一下。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"수송선이란 무기가 없고 물건을 운송하는 기체를 말하는 거야.","JPN":"輸送船とは武装せずに物を運送する機体のことさ。","ENG":"This is a CARGO ship. Which means this ship transports cargo; it doesn’t carry weapons.","TWN":"所謂的貨機呢，機身不會有任何武裝，是單純拿來運送物資的。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래서, 무기가 아무것도 없다는 뜻이야?","JPN":"つまり、武器は一つもないってこと？","ENG":"So we don’t have any weapons?","TWN":"意思是你們沒有任何的武器？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아니! 너희들이 무기라는 뜻이지!","JPN":"いや？　あんたたちが武器っていう意味だ！","ENG":"No! YOU are the weapons.","TWN":"不！意思是，你們就是武器！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"바로 사출시킬 테니까 잘 부탁한다, 코핀 컴퍼니 친구들!","JPN":"すぐに射出してやるからよろしく頼むぜ、コフィンカンパニーさんよ！","ENG":"I’m sending you out right now. Good luck, Coffin Company!","TWN":"我要立刻彈出，拜託你們囉，科芬公司的朋友們！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 아저씨! 잠깐!","JPN":"お、おじさん！　ちょっと待ってよ！","ENG":"M-Mr. Mason! Wait!","TWN":"大叔！先等一下！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"늦었어요, 미나 양. 롤러코스터라도 타러 왔다고 생각하세요.","JPN":"間に合いません、ミナさん。ジェットコースターに乗りに来たとでも思いましょう。","ENG":"It’s too late, Mina. Let’s just pretend that we’re on a roller coaster.","TWN":"米娜，來不及了，你就當他們是坐雲霄飛車來的吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으아아악!!","JPN":"うわああーっ！！","ENG":"Gaaaah!","TWN":"呃啊啊！！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};